#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
int n,m;
const int N=1e5+10,M=2e5+10;
struct Graph
{
	int head[N],des[M],nxt[M],cnt,w[M];
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[head[x]=cnt]=y;}
}a;
int dfn[N],low[N],dep,stk[N],Estk[N],Etop,top;
bool isc[N],ans[N],vs[N];
inline void tarjan(int u)
{
	dfn[u]=low[u]=++dep;stk[++top]=u;
	grep(a,u,i)
	{
		int v=a.des[i],tmp=Etop;
		if(!vs[i>>1])Estk[++Etop]=i>>1,vs[i>>1]=1;
		if(!dfn[v])
		{
			tarjan(v);low[u]=min(low[u],low[v]);
			if(dfn[u]==low[v])
			{
				int dn=1;do{++dn;}while(stk[top--]^v);
				if(Etop-tmp==dn)while(tmp<Etop)ans[Estk[Etop--]]=1;
				else Etop=tmp;
			}
		}
		else low[u]=min(low[u],dfn[v]);
	}
}
int main()
{
	n=read();m=read();a.cnt=1;
	rep(1,m,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	rep(1,n,i)if(!dfn[i])tarjan(i);
	top=0;drep(m,1,i)if(ans[i])stk[++top]=i;
	printf("%d\n",top);while(top)printf("%d ",stk[top--]);
	return 0;
}
